import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Bell, X, CheckCircle, AlertCircle } from 'lucide-react';
import { usePushNotifications } from '../../hooks/usePushNotifications';

const PushNotificationPrompt = () => {
  const [showPrompt, setShowPrompt] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const { isSupported, isSubscribed, hasAskedPermission, subscribeUser } = usePushNotifications();

  useEffect(() => {
    // Afficher le prompt si :
    // - Les notifications sont supportées
    // - On a vérifié l'état d'abonnement
    // - L'utilisateur n'est pas abonné
    // - La permission n'a pas été refusée
    if (isSupported && hasAskedPermission && !isSubscribed && Notification.permission !== 'denied') {
      // Afficher immédiatement
      setShowPrompt(true);
    }
  }, [isSupported, hasAskedPermission, isSubscribed]);

  const handleAccept = async () => {
    setIsProcessing(true);
    try {
      const success = await subscribeUser();
      if (success) {
        setShowPrompt(false);
      }
    } catch (error) {
      console.error('Erreur lors de l\'abonnement:', error);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDecline = () => {
    setShowPrompt(false);
  };

  if (!showPrompt) return null;

  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0, y: 50, scale: 0.9 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        exit={{ opacity: 0, y: 50, scale: 0.9 }}
        transition={{ duration: 0.3, ease: "easeOut" }}
        className="fixed bottom-4 right-4 z-[10000] max-w-sm"
      >
        <div className="bg-white rounded-xl shadow-2xl border border-gray-200/50 p-4 backdrop-blur-sm">
          {/* Header */}
          <div className="flex items-start space-x-3 mb-3">
            <div className="flex-shrink-0">
              <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center">
                <Bell size={20} className="text-blue-600" />
              </div>
            </div>
            <div className="flex-1">
              <h3 className="font-semibold text-gray-900 text-sm">
                Activer les notifications
              </h3>
              <p className="text-xs text-gray-600 mt-1">
                Recevez des alertes importantes sur vos prêts et paiements
              </p>
            </div>
            <button
              onClick={handleDecline}
              className="flex-shrink-0 p-1 rounded-full hover:bg-gray-100 transition-colors duration-200"
            >
              <X size={16} className="text-gray-400" />
            </button>
          </div>

          {/* Actions */}
          <div className="flex space-x-2">
            <button
              onClick={handleDecline}
              disabled={isProcessing}
              className="flex-1 px-3 py-2 text-xs font-medium text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors duration-200 disabled:opacity-50"
            >
              Plus tard
            </button>
            <button
              onClick={handleAccept}
              disabled={isProcessing}
              className="flex-1 px-3 py-2 text-xs font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors duration-200 disabled:opacity-50 flex items-center justify-center space-x-1"
            >
              {isProcessing ? (
                <>
                  <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin" />
                  <span>Activation...</span>
                </>
              ) : (
                <>
                  <CheckCircle size={14} />
                  <span>Activer</span>
                </>
              )}
            </button>
          </div>

          {/* Info supplémentaire */}
          <div className="mt-3 pt-3 border-t border-gray-100">
            <div className="flex items-center space-x-2 text-xs text-gray-500">
              <AlertCircle size={12} />
              <span>Vous pouvez modifier ce paramètre à tout moment</span>
            </div>
          </div>
        </div>
      </motion.div>
    </AnimatePresence>
  );
};

export default PushNotificationPrompt;
